void set_task_privilege(k_tid_t tid, privilege_level_t level)
{
    uint32_t tid_hash = (uint32_t)tid % CONFIG_MAX_THREAD_BYTES;
    task_privileges[tid_hash] = level;
    LOG_INF("Set privilege level %d for task %p (hash: %u)", level, tid, tid_hash);
}

privilege_level_t get_task_privilege(k_tid_t tid)
{
    uint32_t tid_hash = (uint32_t)tid % CONFIG_MAX_THREAD_BYTES;
    return task_privileges[tid_hash];
}

bool check_privilege(k_tid_t tid, privilege_level_t required_level)
{
    privilege_level_t current_level = get_task_privilege(tid);
    return current_level >= required_level;
}

uint32_t calculate_crc32(const uint8_t *data, size_t len)
{
    uint32_t crc = 0xFFFFFFFF;
    for (size_t i = 0; i < len; i++) {
        crc ^= data[i];
        for (int j = 0; j < 8; j++) {
            crc = (crc >> 1) ^ (0xEDB88320 & -(crc & 1));
        }
    }
    return ~crc;
}

int flash_write_config(const system_config_t *config)
{
    int ret;
    const struct flash_area *fa;
    
    ret = flash_area_open(FLASH_AREA_ID, &fa);
    if (ret) {
        LOG_ERR("Failed to open flash area: %d", ret);
        return ret;
    }

    ret = flash_area_erase(fa, CONFIG_OFFSET, CONFIG_SIZE);
    if (ret) {
        LOG_ERR("Failed to erase flash: %d", ret);
        flash_area_close(fa);
        return ret;
    }

    ret = flash_area_write(fa, CONFIG_OFFSET, config, sizeof(system_config_t));
    if (ret) {
        LOG_ERR("Failed to write flash: %d", ret);
    } else {
        LOG_INF("Config written to flash successfully");
    }

    flash_area_close(fa);
    return ret;
}

